import{_ as a,a as e,b as d,c as s}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as l,o as i,c as o,a2 as n}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Додавання каналу S3","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/upload/s3.md","filePath":"uk-UA/upload/s3.md","lastUpdated":1781962217000}'),c={name:"uk-UA/upload/s3.md"};function r(p,t,h,u,b,m){return i(),o("div",null,[...t[0]||(t[0]=[n(`<h1 id="додавання-каналу-s3" tabindex="-1">Додавання каналу S3 <a class="header-anchor" href="#додавання-каналу-s3" aria-label="Permalink to &quot;Додавання каналу S3&quot;">​</a></h1><h2 id="коли-це-наикращии-варіант" tabindex="-1">Коли це найкращий варіант <a class="header-anchor" href="#коли-це-наикращии-варіант" aria-label="Permalink to &quot;Коли це найкращий варіант&quot;">​</a></h2><p>Використовуйте канал S3, якщо:</p><ul><li>хочете підключити будь-яке S3-сумісне об&#39;єктне сховище, наприклад Cloudflare R2, Backblaze B2, MinIO, AWS S3 або іншого сумісного провайдера;</li><li>вам зручна стандартна модель налаштування S3: <code>Endpoint</code>, Access Key і Secret Key;</li><li>не хочете використовувати нативний Cloudflare R2 binding або ваш провайдер сховища не є Cloudflare R2.</li></ul><h2 id="що-підготувати-заздалегідь" tabindex="-1">Що підготувати заздалегідь <a class="header-anchor" href="#що-підготувати-заздалегідь" aria-label="Permalink to &quot;Що підготувати заздалегідь&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Потрібно</th><th>Навіщо це потрібно</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>API endpoint S3 для об&#39;єктного сховища.</td></tr><tr><td>Назва bucket</td><td>Bucket, у якому зберігатимуться файли.</td></tr><tr><td>Region</td><td>Регіон сховища. Для Cloudflare R2 зазвичай це <code>auto</code>.</td></tr><tr><td>Access Key ID</td><td>Ідентифікатор ключа доступу S3.</td></tr><tr><td>Secret Access Key</td><td>Секретний ключ доступу S3.</td></tr><tr><td>CDN domain</td><td>Необов&#39;язковий власний домен для доступу до файлів.</td></tr></tbody></table><p>Приклад для Cloudflare R2 через S3 API:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: copied from the Cloudflare R2 API token</span></span>
<span class="line"><span>Secret Access Key: copied from the Cloudflare R2 API token</span></span></code></pre></div><h2 id="де-додати-канал" tabindex="-1">Де додати канал <a class="header-anchor" href="#де-додати-канал" aria-label="Permalink to &quot;Де додати канал&quot;">​</a></h2><ol><li>Відкрийте системні налаштування.</li><li>Перейдіть до налаштувань завантаження.</li><li>Натисніть Add Channel у правому верхньому куті.</li><li>Виберіть <code>S3</code>.</li></ol><h2 id="поля-налаштування" tabindex="-1">Поля налаштування <a class="header-anchor" href="#поля-налаштування" aria-label="Permalink to &quot;Поля налаштування&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Поле</th><th>Що означає</th><th>Обов&#39;язково</th></tr></thead><tbody><tr><td>Назва каналу</td><td>Зручна назва S3-каналу, наприклад <code>s3test</code> або <code>R2-S3</code>.</td><td>Так</td></tr><tr><td>Enable channel</td><td>Визначає, чи бере канал участь у виборі сховища для завантаження.</td><td>Рекомендовано</td></tr><tr><td>Endpoint</td><td>Повний endpoint S3-сервісу, включно з <code>https://</code>.</td><td>Так</td></tr><tr><td>Custom CDN domain</td><td>Необов&#39;язково. Якщо вказано, згенеровані посилання на файли використовуватимуть цей домен.</td><td>Ні</td></tr><tr><td>Bucket name</td><td>Назва bucket, наприклад <code>s3test</code> або <code>img-r2</code>.</td><td>Так</td></tr><tr><td>Bucket region</td><td>Регіон. Для Cloudflare R2 зазвичай <code>auto</code>.</td><td>Так</td></tr><tr><td>Access Key ID</td><td>Ідентифікатор ключа доступу S3.</td><td>Так</td></tr><tr><td>Secret Access Key</td><td>Секретний ключ доступу S3.</td><td>Так</td></tr><tr><td>Path-style access</td><td>Перемикач сумісності. Типово вимкнений. Деякі MinIO, OpenList або self-hosted S3-сервіси можуть його вимагати.</td><td>Ні</td></tr><tr><td>Quota limit</td><td>Визначає, чи враховується місткість каналу під час вибору сховища.</td><td>Ні</td></tr><tr><td>Capacity limit</td><td>Потрібен після ввімкнення quota limit, наприклад <code>10 GB</code>.</td><td>Так, якщо ввімкнено quota limit</td></tr><tr><td>Threshold</td><td>Зупиняє запис після досягнення цього відсотка використання, наприклад <code>90%</code>.</td><td>Так, якщо ввімкнено quota limit</td></tr><tr><td>Remark</td><td>Нотатки для власного обслуговування.</td><td>Ні</td></tr></tbody></table><h2 id="створення-s3-api-keys-для-cloudflare-r2" tabindex="-1">Створення S3 API keys для Cloudflare R2 <a class="header-anchor" href="#створення-s3-api-keys-для-cloudflare-r2" aria-label="Permalink to &quot;Створення S3 API keys для Cloudflare R2&quot;">​</a></h2><ol><li>Відкрийте Cloudflare Dashboard.</li><li>Перейдіть до <code>R2 Object Storage</code>.</li><li>Знайдіть <code>Manage R2 API Tokens</code> або пункт керування API-токенами.</li></ol><p>![Вхід до R2 API token](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>Створіть R2 API token із доступом до потрібного bucket.</li></ol><p><img src="`+a+'" alt="Створення account API token" loading="lazy"></p><ol start="5"><li>Скопіюйте згенеровані <code>Access Key ID</code> і <code>Secret Access Key</code>.</li></ol><p><img src="'+e+'" alt="Копіювання значень токена" loading="lazy"></p><ol start="6"><li>Поверніться на сторінку R2 bucket і перевірте назву bucket.</li><li>Запишіть S3 API endpoint для облікового запису. Зазвичай він має такий вигляд:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="налаштування" tabindex="-1">Налаштування <a class="header-anchor" href="#налаштування" aria-label="Permalink to &quot;Налаштування&quot;">​</a></h2><ol><li>Відкрийте налаштування завантаження.</li><li>Натисніть Add Channel.</li><li>Виберіть <code>S3</code>.</li><li>Введіть зрозумілу назву каналу, наприклад <code>s3test</code>.</li><li>У полі <code>Endpoint</code> введіть S3 API endpoint.</li><li>Якщо використовуєте власний CDN, введіть його в <code>Custom CDN domain</code>; якщо ні, залиште поле порожнім.</li><li>Введіть назву bucket.</li><li>Введіть region. Для прикладу з Cloudflare R2 використовуйте <code>auto</code>.</li><li>Введіть Access Key ID і Secret Access Key.</li><li>Залиште path-style access вимкненим, якщо провайдер явно не вимагає іншого.</li><li>Якщо потрібен контроль місткості, увімкніть quota limit і введіть capacity limit та threshold.</li><li>Натисніть Save.</li></ol><p><img src="'+d+'" alt="Додавання S3 конфігурації" loading="lazy"></p><h2 id="як-перевірити" tabindex="-1">Як перевірити <a class="header-anchor" href="#як-перевірити" aria-label="Permalink to &quot;Як перевірити&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Перевірка</th><th>Як перевірити</th></tr></thead><tbody><tr><td>Картка каналу з&#39;явилася</td><td>Після збереження на сторінці налаштувань завантаження має бути картка S3-каналу.</td></tr><tr><td>Канал увімкнений</td><td>Перемикач у правому верхньому куті картки має залишатися ввімкненим.</td></tr><tr><td>Основні поля збережені</td><td>У деталях мають відображатися Endpoint, Bucket, Region, path-style access та пов&#39;язані поля.</td></tr><tr><td>Завантаження працює</td><td>Завантажте тестове зображення й переконайтеся, що об&#39;єкт з&#39;явився в цільовому bucket.</td></tr><tr><td>Посилання відкривається</td><td>Посилання на зображення, повернене після завантаження, має відкриватися нормально.</td></tr><tr><td>Показ місткості працює</td><td>Якщо ввімкнено quota limit, картка має показувати використану місткість і налаштований ліміт.</td></tr></tbody></table><p>Статистика місткості S3 рахується за локальними записами файлів в ImgBed, а не через запит до bucket провайдера в реальному часі. Після збереження S3-конфігурації система перераховує облік квоти за поточними записами D1.</p><p><img src="'+s+`" alt="Успішний запит квоти" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="чи-потрібно-вмикати-path-style-access" tabindex="-1">Чи потрібно вмикати path-style access? <a class="header-anchor" href="#чи-потрібно-вмикати-path-style-access" aria-label="Permalink to &quot;Чи потрібно вмикати path-style access?&quot;">​</a></h3><p>Зазвичай ні.</p><p>Увімкніть його тільки тоді, коли ваш S3-сумісний провайдер не підтримує virtual-hosted-style URL або коли документація провайдера прямо вимагає path-style access. Це може знадобитися для деяких MinIO, self-hosted S3 та OpenList-сумісних endpoint.</p><h3 id="для-чого-потрібен-cdn-domain" tabindex="-1">Для чого потрібен CDN domain? <a class="header-anchor" href="#для-чого-потрібен-cdn-domain" aria-label="Permalink to &quot;Для чого потрібен CDN domain?&quot;">​</a></h3><p>Якщо перед bucket стоїть CDN або власний домен доступу, вкажіть його тут.</p><p>Після налаштування згенеровані посилання на файли використовуватимуть цей домен. Якщо CDN не використовується, залиште поле порожнім.</p><h3 id="чому-завантаження-не-проходить" tabindex="-1">Чому завантаження не проходить? <a class="header-anchor" href="#чому-завантаження-не-проходить" aria-label="Permalink to &quot;Чому завантаження не проходить?&quot;">​</a></h3><p>Спершу перевірте такі речі:</p><ol><li>Endpoint містить повну адресу з <code>https://</code>.</li><li>Назва bucket правильна.</li><li>Region відповідає вимогам провайдера.</li><li>Access Key ID і Secret Access Key скопійовані повністю.</li><li>Ключ має право запису в цільовий bucket.</li><li>Провайдер не вимагає path-style access, або цей режим увімкнений, якщо потрібен.</li></ol><h2 id="короткии-чекліст" tabindex="-1">Короткий чекліст <a class="header-anchor" href="#короткии-чекліст" aria-label="Permalink to &quot;Короткий чекліст&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Підготувати S3 Endpoint, Bucket, Region, Access Key і Secret Key</span></span>
<span class="line"><span>-&gt; Відкрити налаштування завантаження</span></span>
<span class="line"><span>-&gt; Додати канал</span></span>
<span class="line"><span>-&gt; Вибрати S3</span></span>
<span class="line"><span>-&gt; Ввести Endpoint / Bucket / Region / Access Key / Secret Key</span></span>
<span class="line"><span>-&gt; За потреби ввести CDN domain</span></span>
<span class="line"><span>-&gt; Типово залишити path-style access вимкненим</span></span>
<span class="line"><span>-&gt; За потреби ввімкнути quota limit</span></span>
<span class="line"><span>-&gt; Зберегти</span></span>
<span class="line"><span>-&gt; Завантажити тестове зображення й перевірити результат</span></span></code></pre></div>`,40)])])}const S=l(c,[["render",r]]);export{g as __pageData,S as default};
